import { useEffect, useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { auth, db } from "../firebase";
import {
  collection,
  setDoc,
  doc,
  query,
  where,
  getDocs,
} from "firebase/firestore";
import { onAuthStateChanged } from "firebase/auth";
import Swal from "sweetalert2";
import Navbar from "../components/Navbar";

export default function Votacao() {
  const location = useLocation();
  const navigate = useNavigate();
  const assembleia = location.state?.assembleia;

  const [usuario, setUsuario] = useState(null);
  const [votoFeito, setVotoFeito] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!assembleia) {
      navigate("/evento");
      return;
    }

    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      if (!user) {
        navigate("/");
        return;
      }

      try {
        // 🔹 Busca dados do usuário logado
        const usuariosSnap = await getDocs(
          query(collection(db, "usuarios"), where("__name__", "==", user.uid))
        );

        if (!usuariosSnap.empty) {
          const dados = usuariosSnap.docs[0].data();
          setUsuario({ ...dados, id: user.uid });

          // 🔎 Verifica se o apartamento já votou nesta assembleia
          const votosRef = collection(db, "votos");
          const votosSnap = await getDocs(
            query(
              votosRef,
              where("idAssembleia", "==", assembleia.idAssembleia),
              where("bloco", "==", dados.bloco),
              where("apartamento", "==", dados.apartamento)
            )
          );

          if (!votosSnap.empty) setVotoFeito(true);
        }
      } catch (err) {
        console.error("Erro ao carregar usuário:", err);
      }

      setLoading(false);
    });

    return () => unsubscribe();
  }, [assembleia, navigate]);

  // ✅ Registrar voto (por apartamento)
  const registrarVoto = async (opcao) => {
    if (!usuario || votoFeito) return;

    try {
      if (!usuario?.bloco || !usuario?.apartamento) {
        Swal.fire("Erro", "Informações do apartamento não encontradas.", "error");
        return;
      }

      // 🔹 ID único por assembleia + apartamento (exemplo: "1-101-assembleia123")
      const votoId = `${usuario.bloco}-${usuario.apartamento}-${assembleia.idAssembleia}`;

      // 🔎 Verifica se já existe voto no mesmo bloco/apartamento
      const q = query(
        collection(db, "votos"),
        where("idAssembleia", "==", assembleia.idAssembleia),
        where("bloco", "==", usuario.bloco),
        where("apartamento", "==", usuario.apartamento)
      );

      const snap = await getDocs(q);
      if (!snap.empty) {
        Swal.fire(
          "Voto já registrado!",
          `O apartamento ${usuario.bloco}-${usuario.apartamento} já realizou o voto.`,
          "warning"
        );
        setVotoFeito(true);
        return;
      }

      // ✅ Registra o voto com ID fixo (garante unicidade)
      await setDoc(doc(db, "votos", votoId), {
        idAssembleia: assembleia.idAssembleia,
        bloco: usuario.bloco,
        apartamento: usuario.apartamento,
        cpf: usuario.cpf,
        idUsuario: usuario.id,
        voto: opcao,
        dataVoto: new Date(),
      });

      setVotoFeito(true);

      Swal.fire({
        title: "Voto registrado!",
        text: `O apartamento ${usuario.bloco}-${usuario.apartamento} registrou o voto em "${opcao}".`,
        icon: "success",
        confirmButtonColor: "#4f46e5",
      });
    } catch (error) {
      console.error(error);
      Swal.fire({
        title: "Erro ao votar",
        text: "Ocorreu um problema ao registrar seu voto.",
        icon: "error",
        confirmButtonColor: "#ef4444",
      });
    }
  };

  // ⏳ Tela de carregamento
  if (loading) {
    return (
      <div className="flex justify-center items-center min-h-screen text-gray-600">
        Carregando assembleia...
      </div>
    );
  }

  // 🚫 Sem assembleia
  if (!assembleia) {
    return (
      <div className="flex justify-center items-center min-h-screen text-gray-600">
        Nenhuma assembleia encontrada.
      </div>
    );
  }

  const dataFormatada = new Date(assembleia.data).toLocaleString("pt-BR", {
    dateStyle: "long",
    timeStyle: "short",
  });

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-100 via-blue-50 to-indigo-100">
      <Navbar mostrarVoltar={true} />

      <div className="max-w-2xl mx-auto bg-white/40 backdrop-blur-md shadow-lg border border-white/30 rounded-3xl p-10 mt-24 text-center">
        <h1 className="text-2xl font-bold text-gray-800 mb-2">
          {assembleia.titulo}
        </h1>
        <p className="text-gray-600 mb-1">{assembleia.descricao}</p>
        <p className="text-gray-500 text-sm mb-6">
          Data: {dataFormatada}
        </p>

        {!votoFeito ? (
          <div className="flex flex-col gap-3 items-center">
            {assembleia.opcoes.map((opcao, index) => (
              <button
                key={index}
                onClick={() => registrarVoto(opcao)}
                className="w-full md:w-3/4 py-3 rounded-xl bg-gradient-to-r from-sky-500 to-indigo-500 text-white font-semibold shadow-md hover:opacity-90 transition"
              >
                {opcao}
              </button>
            ))}
          </div>
        ) : (
          <div className="mt-6 text-green-600 font-medium">
            ✅ O apartamento {usuario.bloco}-{usuario.apartamento} já registrou
            o voto. Obrigado pela participação!
          </div>
        )}
      </div>
    </div>
  );
}
